declare module '*.png' {
  const value: number;
  export default value;
}

declare module '*.jpg' {
  const value: number;
  export default value;
}

declare module '*.jpeg' {
  const value: number;
  export default value;
}

/** Lottie JSON sources (object) for `lottie-react-native`. */
declare module '*.json' {
  const value: Record<string, unknown>;
  export default value;
}
